import React, { useState, useEffect } from 'react';
import { FiCamera as Camera, FiCheckCircle as CheckCircle2, FiXCircle as XCircle, FiAlertTriangle as AlertTriangle, FiInfo } from 'react-icons/fi';
import { MdFingerprint as Fingerprint } from 'react-icons/md';
import Papa from 'papaparse';

const ScanCheckin = ({ user }) => {
    const [scanning, setScanning] = useState(false);
    const [result, setResult] = useState(null); // 'success', 'error_location'
    const [locationInfo, setLocationInfo] = useState(null);
    const [activeOD, setActiveOD] = useState(null);
    const [labMetadata, setLabMetadata] = useState(null);

    useEffect(() => {
        // 1. Find the latest APPROVED OD for this student
        const allRequests = JSON.parse(localStorage.getItem('all_od_requests') || '[]');
        const myActiveOD = allRequests
            .filter(r => r.studentId === user.id && r.status === 'APPROVED')
            .sort((a, b) => b.id - a.id)[0];

        if (myActiveOD) {
            setActiveOD(myActiveOD);

            // 2. Mark as Mock Scan Opened to pause SystemMonitor notifications
            if (!myActiveOD.mockScanOpened) {
                const updatedRequests = allRequests.map(r =>
                    r.id === myActiveOD.id ? { ...r, mockScanOpened: true } : r
                );
                localStorage.setItem('all_od_requests', JSON.stringify(updatedRequests));

                // Also update student's personal history
                const studentHistory = JSON.parse(localStorage.getItem(`od_requests_${user.id}`) || '[]');
                const updatedHistory = studentHistory.map(r =>
                    r.id === myActiveOD.id ? { ...r, mockScanOpened: true } : r
                );
                localStorage.setItem(`od_requests_${user.id}`, JSON.stringify(updatedHistory));
            }

            // 3. Fetch Lab Metadata (Floor, BSSID)
            fetch('/MAC_address.csv')
                .then(res => res.text())
                .then(csv => {
                    const parsed = Papa.parse(csv, { header: true, skipEmptyLines: true }).data;
                    const meta = parsed.find(row => row.className === myActiveOD.labName);
                    setLabMetadata(meta);
                });
        }
    }, [user.id]);

    const handleCheckIn = (scannedData) => {
        setScanning(true);
        setResult(null);

        setTimeout(() => {
            try {
                const data = JSON.parse(scannedData);
                if (data.type && data.name) {
                    // Update global live presence store
                    const presence = JSON.parse(localStorage.getItem('live_presence') || '{}');
                    presence[user.id] = {
                        type: data.type,
                        name: data.name,
                        checkInTime: new Date().toLocaleTimeString(),
                        facultyId: data.id,
                        floor: data.floor || 'Unknown',
                        bssid: data.bssid || 'N/A'
                    };
                    localStorage.setItem('live_presence', JSON.stringify(presence));

                    setLocationInfo(data);
                    setResult('success');
                } else {
                    setResult('error_location');
                }
            } catch (e) {
                setResult('error_location');
            }
            setScanning(false);
        }, 1200);
    };

    return (
        <div className="max-w-md mx-auto py-12 px-4">
            <div className="text-center mb-10">
                <h2 className="text-4xl font-extrabold text-white leading-tight tracking-tight">Scanner Portal</h2>
                <p className="text-gray-400 mt-4 text-sm font-medium">Verify your lab presence via encrypted beacon signals.</p>
            </div>

            {activeOD ? (
                <div className="mb-8 bg-blue-500/5 border border-blue-500/20 rounded-3xl p-6 animate-fade-in">
                    <div className="flex items-center space-x-4 mb-4">
                        <div className="bg-blue-500/10 p-3 rounded-2xl text-blue-500">
                            <FiInfo size={20} />
                        </div>
                        <div>
                            <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Active Approved OD</p>
                            <p className="text-lg font-bold text-white leading-tight">{activeOD.labName}</p>
                        </div>
                    </div>
                    <div className="grid grid-cols-2 gap-4 mt-2 pt-4 border-t border-white/5">
                        <div>
                            <p className="text-[9px] font-black text-gray-500 uppercase tracking-widest">Purpose</p>
                            <p className="text-xs font-bold text-gray-300 truncate">{activeOD.purpose}</p>
                        </div>
                        <div className="text-right">
                            <p className="text-[9px] font-black text-gray-500 uppercase tracking-widest">Status</p>
                            <p className="text-xs font-black text-emerald-400 uppercase tracking-widest">Time Tracking Paused</p>
                        </div>
                    </div>
                </div>
            ) : (
                <div className="mb-8 bg-amber-500/5 border border-amber-500/20 rounded-3xl p-6 text-center animate-fade-in">
                    <p className="text-sm font-bold text-amber-500">No approved OD found. <br /><span className="text-gray-500 text-xs mt-1 block">Manual check-in will be rejected.</span></p>
                </div>
            )}

            <div className="bg-[#141417] rounded-[2.5rem] shadow-2xl border border-white/5 overflow-hidden relative">
                {/* Camera simulation area */}
                <div className="bg-gray-900 aspect-square relative flex items-center justify-center">
                    {scanning ? (
                        <div className="absolute inset-0 bg-[#0a0a0b]/90 flex flex-col items-center justify-center backdrop-blur-md z-10 transition-all">
                            <div className="w-20 h-20 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-6 shadow-[0_0_30px_rgba(59,130,246,0.3)]"></div>
                            <p className="text-blue-400 font-black uppercase text-xs tracking-widest animate-pulse">Establishing handshake...</p>
                        </div>
                    ) : result === null ? (
                        <div className="text-center p-10">
                            <div className="w-64 h-64 border-2 border-dashed border-gray-800 rounded-[3rem] mb-10 flex items-center justify-center bg-white/5 relative group">
                                <Camera className="text-gray-700 group-hover:text-blue-500 transition-colors" size={56} />
                                <div className="absolute inset-0 border-2 border-blue-500/20 rounded-[3rem] animate-glow scale-110 opacity-0 group-hover:opacity-100 transition-opacity"></div>

                                {/* Overlay scanner frame */}
                                <div className="absolute inset-8 border-2 border-white/10 rounded-3xl pointer-events-none">
                                    <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-blue-500 rounded-tl-2xl -ml-1 -mt-1"></div>
                                    <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-blue-500 rounded-tr-2xl -mr-1 -mt-1"></div>
                                    <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-blue-500 rounded-bl-2xl -ml-1 -mb-1"></div>
                                    <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-blue-500 rounded-br-2xl -mr-1 -mb-1"></div>
                                </div>
                            </div>

                            {activeOD && labMetadata ? (
                                <button
                                    onClick={() => handleCheckIn(JSON.stringify({
                                        type: 'LAB',
                                        name: activeOD.labName,
                                        id: activeOD.labInchargeId || 'LAB001',
                                        floor: labMetadata.floor || 'Unknown Floor',
                                        bssid: labMetadata.bssid || '00:00:00:00:00:00'
                                    }))}
                                    className="w-full py-5 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl text-[10px] font-black shadow-xl shadow-blue-900/40 transition-all active:scale-95 uppercase tracking-[0.2em]"
                                >
                                    Simulate Scan for {activeOD.labName}
                                </button>
                            ) : (
                                <p className="text-gray-500 text-xs font-black uppercase tracking-widest">Awaiting Proximity Beacon...</p>
                            )}
                        </div>
                    ) : (
                        <div className="bg-[#141417] absolute inset-0 flex flex-col items-center justify-center p-10 text-center animate-fade-in z-20">
                            {result === 'success' ? (
                                <>
                                    <div className="bg-blue-500/10 text-blue-500 rounded-[2rem] p-8 mb-8 border border-blue-500/20 shadow-[0_0_50px_rgba(59,130,246,0.1)]">
                                        <CheckCircle2 size={72} />
                                    </div>
                                    <h3 className="text-3xl font-black text-white mb-8 tracking-tight">Check-in Success</h3>
                                    <div className="w-full space-y-5 mb-10 text-left bg-white/5 p-8 rounded-3xl border border-white/5 shadow-inner">
                                        <div>
                                            <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-2">Resource</p>
                                            <p className="text-xl font-bold text-white italic">{locationInfo.name}</p>
                                        </div>
                                        <div>
                                            <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-2">Location floor</p>
                                            <p className="text-xl font-bold text-white">{locationInfo.floor || 'N/A'}</p>
                                        </div>
                                        <div className="pt-4 border-t border-white/5">
                                            <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-2">VLAN Identifier</p>
                                            <p className="text-lg font-black text-emerald-400 tracking-tighter uppercase">{locationInfo.bssid}</p>
                                        </div>
                                    </div>
                                </>
                            ) : (
                                <>
                                    <div className="bg-red-500/10 text-red-500 rounded-[2rem] p-8 mb-8 border border-red-500/20 shadow-[0_0_50px_rgba(239,68,68,0.1)]">
                                        <XCircle size={72} />
                                    </div>
                                    <h3 className="text-3xl font-black text-white mb-4">Auth Error</h3>
                                    <p className="text-gray-500 mb-10 text-base font-medium leading-relaxed">Invalid beacon signal or mismatched MAC signature. Please try again.</p>
                                </>
                            )}
                            <button
                                onClick={() => setResult(null)}
                                className="w-full py-5 bg-white text-black rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-gray-200 transition-all active:scale-95 shadow-2xl"
                            >
                                DISCARD & RESCAN
                            </button>
                        </div>
                    )}
                </div>

                <div className="bg-white/5 p-8 flex items-start space-x-6 border-t border-white/5">
                    <Fingerprint className="text-blue-500 mt-1 shrink-0" size={32} />
                    <div>
                        <p className="text-sm text-white font-black uppercase tracking-[0.2em]">IoT Backbone Active</p>
                        <p className="text-xs text-gray-500 mt-2 leading-relaxed">
                            BSSID monitoring and Floor verification are enabled. Your precision location is mirrored to Faculty portals.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ScanCheckin;
